124→func resumeFromCurrentBranch(ctx context.Context, branchName string, force bool) error {
125→	repo, err := openRepository(ctx)
126→	if err != nil {
127→		return fmt.Errorf("not a git repository: %w", err)
128→	}
129→
130→	// Find a commit with an Entire-Checkpoint trailer, looking at branch-only commits
131→	result, err := findBranchCheckpoint(repo, branchName)
132→	if err != nil {
133→		return err
134→	}
135→	if len(result.checkpointIDs) == 0 {
136→		fmt.Fprintf(os.Stderr, "No Entire checkpoint found on branch '%s'\n", branchName)
137→		return nil
138→	}
139→
140→	// If there are newer commits without checkpoints, ask for confirmation.
141→	// Merge commits (e.g., from merging main) don't count as "work" and are skipped silently.
142→	if result.newerCommitsExist && !force {
143→		fmt.Fprintf(os.Stderr, "Found checkpoint in an older commit.\n")
144→		fmt.Fprintf(os.Stderr, "There are %d newer commit(s) on this branch without checkpoints.\n", result.newerCommitCount)
145→		fmt.Fprintf(os.Stderr, "Checkpoint from: %s %s\n\n", result.commitHash[:7], firstLine(result.commitMessage))
146→
147→		shouldResume, err := promptResumeFromOlderCheckpoint()
148→		if err != nil {
149→			return err
150→		}
151→		if !shouldResume {
152→			fmt.Fprintf(os.Stderr, "Resume cancelled.\n")
153→			return nil
154→		}
155→	}
156→
157→	// Multiple checkpoints (squash merge): restore all sessions
158→	if len(result.checkpointIDs) > 1 {
159→		return resumeMultipleCheckpoints(ctx, repo, result.checkpointIDs, force)
160→	}
161→
162→	// Single checkpoint: existing behavior (unchanged)
163→	checkpointID := result.checkpointIDs[0]
164→
165→	// Get metadata branch tree for lookups
166→	metadataTree, err := strategy.GetMetadataBranchTree(repo)
167→	if err != nil {
168→		// No local metadata branch, check if remote has it
169→		return checkRemoteMetadata(ctx, repo, checkpointID)
170→	}
171→
172→	// Look up metadata from sharded path
173→	metadata, err := strategy.ReadCheckpointMetadata(metadataTree, checkpointID.Path())
174→	if err != nil {
175→		// Checkpoint exists in commit but no local metadata - check remote
176→		return checkRemoteMetadata(ctx, repo, checkpointID)
177→	}
178→
179→	return resumeSession(ctx, metadata.SessionID, checkpointID, force)
