182→// resumeMultipleCheckpoints restores sessions from multiple checkpoint IDs.
183→// This handles squash merge commits where multiple Entire-Checkpoint trailers
184→// are present in a single commit message. Each checkpoint is looked up independently
185→// and missing metadata is skipped (best-effort).
186→func resumeMultipleCheckpoints(ctx context.Context, repo *git.Repository, checkpointIDs []id.CheckpointID, force bool) error {
187→	logCtx := logging.WithComponent(ctx, "resume")
188→
189→	// Get metadata branch tree (try local first, then remote)
190→	metadataTree, err := strategy.GetMetadataBranchTree(repo)
191→	if err != nil {
192→		// Try fetching from remote
193→		logging.Debug(logCtx, "metadata branch not available locally, trying remote")
194→		if fetchErr := FetchMetadataBranch(ctx); fetchErr != nil {
195→			// If fetch also fails, try remote tree directly
196→			remoteTree, remoteErr := strategy.GetRemoteMetadataBranchTree(repo)
197→			if remoteErr != nil {
198→				fmt.Fprintf(os.Stderr, "Checkpoint metadata not available locally or on remote\n")
199→				return nil //nolint:nilerr // Informational message, not a fatal error
200→			}
201→			metadataTree = remoteTree
202→		} else {
203→			metadataTree, err = strategy.GetMetadataBranchTree(repo)
204→			if err != nil {
205→				fmt.Fprintf(os.Stderr, "Checkpoint metadata not available after fetch\n")
206→				return nil //nolint:nilerr // Informational message, not a fatal error
207→			}
208→		}
209→	}
210→
211→	strat := GetStrategy(ctx)
212→	var allSessions []strategy.RestoredSession
213→
214→	for _, cpID := range checkpointIDs {
215→		metadata, metaErr := strategy.ReadCheckpointMetadata(metadataTree, cpID.Path())
216→		if metaErr != nil {
217→			logging.Debug(logCtx, "skipping checkpoint without metadata",
218→				slog.String("checkpoint_id", cpID.String()),
219→				slog.String("error", metaErr.Error()),
220→			)
221→			continue
222→		}
223→
224→		point := strategy.RewindPoint{
225→			IsLogsOnly:   true,
226→			CheckpointID: cpID,
227→			Agent:        metadata.Agent,
228→		}
229→
230→		sessions, restoreErr := strat.RestoreLogsOnly(ctx, point, force)
231→		if restoreErr != nil {
232→			logging.Debug(logCtx, "skipping checkpoint: restore failed",
233→				slog.String("checkpoint_id", cpID.String()),
234→				slog.String("error", restoreErr.Error()),
235→			)
236→			continue
237→		}
238→		if len(sessions) == 0 {
239→			logging.Debug(logCtx, "skipping checkpoint: no sessions restored",
240→				slog.String("checkpoint_id", cpID.String()),
241→			)
242→			continue
243→		}
244→
245→		allSessions = deduplicateSessions(allSessions, sessions)
246→	}
247→
248→	if len(allSessions) == 0 {
249→		fmt.Fprintf(os.Stderr, "No session metadata found for checkpoints in this commit\n")
250→		return nil
251→	}
252→
253→	logging.Debug(logCtx, "resume multiple checkpoints completed",
254→		slog.Int("checkpoint_count", len(checkpointIDs)),
255→		slog.Int("session_count", len(allSessions)),
256→	)
257→
258→	return displayRestoredSessions(allSessions)
259→}
260→
261→// deduplicateSessions merges new sessions into existing, keeping the one with the latest
262→// CreatedAt when a SessionID appears more than once. This handles squash merges where the
263→// same session may be referenced by multiple checkpoints.
264→func deduplicateSessions(existing, incoming []strategy.RestoredSession) []strategy.RestoredSession {
265→	type entry struct {
266→		index     int
267→		createdAt time.Time
268→	}
269→
270→	seen := make(map[string]entry, len(existing))
271→	for i, s := range existing {
272→		seen[s.SessionID] = entry{index: i, createdAt: s.CreatedAt}
273→	}
274→
275→	for _, sess := range incoming {
276→		if prev, exists := seen[sess.SessionID]; exists {
277→			// Keep the one with the later CreatedAt (more complete transcript)
278→			if sess.CreatedAt.After(prev.createdAt) {
279→				existing[prev.index] = sess
280→				seen[sess.SessionID] = entry{index: prev.index, createdAt: sess.CreatedAt}
281→			}
282→		} else {
283→			seen[sess.SessionID] = entry{index: len(existing), createdAt: sess.CreatedAt}
284→			existing = append(existing, sess)
285→		}
286→	}
287→
288→	return existing
289→}
290→
291→// branchCheckpointResult contains the result of searching for a checkpoint on a branch.
292→type branchCheckpointResult struct {
293→	checkpointIDs     []id.CheckpointID
294→	commitHash        string
295→	commitMessage     string
296→	newerCommitsExist bool // true if there are branch-only commits (not merge commits) without checkpoints
297→	newerCommitCount  int  // count of branch-only commits without checkpoints
298→}
299→
300→// findBranchCheckpoint finds the most recent commit with an Entire-Checkpoint trailer
301→// among commits that are unique to this branch (not reachable from the default branch).
302→// This handles the case where main has been merged into the feature branch.
303→func findBranchCheckpoint(repo *git.Repository, branchName string) (*branchCheckpointResult, error) {
304→	result := &branchCheckpointResult{}
305→
306→	// Get HEAD commit
307→	head, err := repo.Head()
308→	if err != nil {
309→		return nil, fmt.Errorf("failed to get HEAD: %w", err)
310→	}
311→
312→	headCommit, err := repo.CommitObject(head.Hash())
313→	if err != nil {
314→		return nil, fmt.Errorf("failed to get HEAD commit: %w", err)
315→	}
316→
317→	// First, check if HEAD itself has a checkpoint (most common case)
318→	if cpIDs := trailers.ParseAllCheckpoints(headCommit.Message); len(cpIDs) > 0 {
319→		result.checkpointIDs = cpIDs
320→		result.commitHash = head.Hash().String()
321→		result.commitMessage = headCommit.Message
322→		result.newerCommitsExist = false
323→		return result, nil
324→	}
325→
326→	// HEAD doesn't have a checkpoint - find branch-only commits
327→	// Get the default branch name
328→	defaultBranch := getDefaultBranchFromRemote(repo)
329→	if defaultBranch == "" {
330→		// Fallback: try common names
331→		for _, name := range []string{"main", "master"} {
332→			if _, err := repo.Reference(plumbing.NewBranchReferenceName(name), true); err == nil {
333→				defaultBranch = name
334→				break
335→			}
336→		}
337→	}
338→
339→	// If we can't find a default branch, or we're on it, just walk all commits
340→	if defaultBranch == "" || defaultBranch == branchName {
341→		return findCheckpointInHistory(headCommit, nil), nil
342→	}
343→
344→	// Get the default branch reference
345→	defaultRef, err := repo.Reference(plumbing.NewBranchReferenceName(defaultBranch), true)
346→	if err != nil {
347→		// Default branch doesn't exist locally, fall back to walking all commits
348→		return findCheckpointInHistory(headCommit, nil), nil //nolint:nilerr // Intentional fallback
349→	}
350→
351→	defaultCommit, err := repo.CommitObject(defaultRef.Hash())
352→	if err != nil {
353→		// Can't get default commit, fall back to walking all commits
354→		return findCheckpointInHistory(headCommit, nil), nil //nolint:nilerr // Intentional fallback
355→	}
356→
357→	// Find merge base
358→	mergeBase, err := headCommit.MergeBase(defaultCommit)
359→	if err != nil || len(mergeBase) == 0 {
360→		// No common ancestor, fall back to walking all commits
361→		return findCheckpointInHistory(headCommit, nil), nil //nolint:nilerr // Intentional fallback
362→	}
363→
364→	// Walk from HEAD to merge base, looking for checkpoint
365→	return findCheckpointInHistory(headCommit, &mergeBase[0].Hash), nil
366→}
367→
368→// findCheckpointInHistory walks commit history from start looking for a checkpoint trailer.
369→// If stopAt is provided, stops when reaching that commit (exclusive).
370→// Returns the first checkpoint found and info about commits between HEAD and the checkpoint.
371→// It distinguishes between merge commits (bringing in other branches) and regular commits
372→// (actual branch work) to avoid false warnings after merging main.
373→func findCheckpointInHistory(start *object.Commit, stopAt *plumbing.Hash) *branchCheckpointResult {
374→	result := &branchCheckpointResult{}
375→	branchWorkCommits := 0 // Regular commits without checkpoints (actual work)
376→	const maxCommits = 100 // Limit search depth
377→	totalChecked := 0
378→
379→	current := start
380→	for current != nil && totalChecked < maxCommits {
381→		// Stop if we've reached the boundary
382→		if stopAt != nil && current.Hash == *stopAt {
383→			break
384→		}
385→
386→		// Check for checkpoint trailer
387→		if cpIDs := trailers.ParseAllCheckpoints(current.Message); len(cpIDs) > 0 {
388→			result.checkpointIDs = cpIDs
389→			result.commitHash = current.Hash.String()
390→			result.commitMessage = current.Message
391→			// Only warn about branch work commits, not merge commits
392→			result.newerCommitsExist = branchWorkCommits > 0
393→			result.newerCommitCount = branchWorkCommits
394→			return result
395→		}
396→
397→		// Only count regular commits (not merge commits) as "branch work"
398→		if current.NumParents() <= 1 {
399→			branchWorkCommits++
400→		}
401→
402→		totalChecked++
403→
404→		// Move to parent (first parent for merge commits - follows the main line)
405→		if current.NumParents() == 0 {
406→			break
407→		}
408→		parent, err := current.Parent(0)
409→		if err != nil {
410→			// Can't get parent, treat as end of history
411→			break
412→		}
413→		current = parent
414→	}
415→
416→	// No checkpoint found
417→	return result
418→}
