420→// promptResumeFromOlderCheckpoint asks the user if they want to resume from an older checkpoint.
421→func promptResumeFromOlderCheckpoint() (bool, error) {
422→	var confirmed bool
423→
424→	form := NewAccessibleForm(
425→		huh.NewGroup(
426→			huh.NewConfirm().
427→				Title("Resume from this older checkpoint?").
428→				Value(&confirmed),
429→		),
430→	)
431→
432→	if err := form.Run(); err != nil {
433→		if errors.Is(err, huh.ErrUserAborted) {
434→			return false, nil
435→		}
436→		return false, fmt.Errorf("failed to get confirmation: %w", err)
437→	}
438→
439→	return confirmed, nil
440→}
441→
442→// checkRemoteMetadata checks if checkpoint metadata exists on origin/entire/checkpoints/v1
443→// and automatically fetches it if available.
444→func checkRemoteMetadata(ctx context.Context, repo *git.Repository, checkpointID id.CheckpointID) error {
445→	// Try to get remote metadata branch tree
446→	remoteTree, err := strategy.GetRemoteMetadataBranchTree(repo)
447→	if err != nil {
448→		fmt.Fprintf(os.Stderr, "Checkpoint '%s' found in commit but session metadata not available\n", checkpointID)
449→		fmt.Fprintf(os.Stderr, "The entire/checkpoints/v1 branch may not exist locally or on the remote.\n")
450→		return nil //nolint:nilerr // Informational message, not a fatal error
451→	}
452→
453→	// Check if the checkpoint exists on the remote
454→	metadata, err := strategy.ReadCheckpointMetadata(remoteTree, checkpointID.Path())
455→	if err != nil {
456→		fmt.Fprintf(os.Stderr, "Checkpoint '%s' found in commit but session metadata not available\n", checkpointID)
457→		return nil //nolint:nilerr // Informational message, not a fatal error
458→	}
459→
460→	// Metadata exists on remote but not locally - fetch it automatically
461→	fmt.Fprintf(os.Stderr, "Fetching session metadata from origin...\n")
462→	if err := FetchMetadataBranch(ctx); err != nil {
463→		fmt.Fprintf(os.Stderr, "Failed to fetch metadata: %v\n", err)
464→		fmt.Fprintf(os.Stderr, "You can try manually: git fetch origin entire/checkpoints/v1:entire/checkpoints/v1\n")
465→		return NewSilentError(errors.New("failed to fetch metadata"))
466→	}
467→
468→	// Now resume the session with the fetched metadata
469→	return resumeSession(ctx, metadata.SessionID, checkpointID, false)
470→}
471→
472→// resumeSession restores and displays the resume command for a specific session.
473→// For multi-session checkpoints, restores ALL sessions and shows commands for each.
474→// If force is false, prompts for confirmation when local logs have newer timestamps.
475→func resumeSession(ctx context.Context, sessionID string, checkpointID id.CheckpointID, force bool) error {
476→	// Read checkpoint metadata first to get agent type (matching rewind pattern)
477→	repo, err := openRepository(ctx)
478→	if err != nil {
479→		return fmt.Errorf("failed to open repository: %w", err)
480→	}
481→
482→	metadataTree, err := strategy.GetMetadataBranchTree(repo)
483→	if err != nil {
484→		return fmt.Errorf("failed to get metadata branch: %w", err)
485→	}
486→
487→	metadata, err := strategy.ReadCheckpointMetadata(metadataTree, checkpointID.Path())
488→	if err != nil {
489→		return fmt.Errorf("failed to read checkpoint metadata: %w", err)
490→	}
491→
492→	// Resolve agent from checkpoint metadata (same as rewind)
493→	ag, err := strategy.ResolveAgentForRewind(metadata.Agent)
494→	if err != nil {
495→		return fmt.Errorf("failed to resolve agent: %w", err)
496→	}
497→
498→	// Initialize logging context with agent
499→	logCtx := logging.WithAgent(logging.WithComponent(ctx, "resume"), ag.Name())
500→
501→	logging.Debug(logCtx, "resume session started",
502→		slog.String("checkpoint_id", checkpointID.String()),
503→		slog.String("session_id", sessionID),
504→	)
505→
506→	// Get worktree root for session directory lookup
507→	repoRoot, err := paths.WorktreeRoot(ctx)
508→	if err != nil {
509→		return fmt.Errorf("failed to get worktree root: %w", err)
510→	}
511→
512→	sessionDir, err := ag.GetSessionDir(repoRoot)
513→	if err != nil {
514→		return fmt.Errorf("failed to determine session directory: %w", err)
515→	}
516→
517→	// Create directory if it doesn't exist
518→	if err := os.MkdirAll(sessionDir, 0o700); err != nil {
519→		return fmt.Errorf("failed to create session directory: %w", err)
520→	}
521→
522→	// Get strategy and restore sessions using full checkpoint data
523→	strat := GetStrategy(ctx)
524→
525→	// Use RestoreLogsOnly via LogsOnlyRestorer interface for multi-session support
526→	// Create a logs-only rewind point with Agent populated (same as rewind)
527→	point := strategy.RewindPoint{
528→		IsLogsOnly:   true,
529→		CheckpointID: checkpointID,
530→		Agent:        metadata.Agent,
531→	}
532→
533→	sessions, restoreErr := strat.RestoreLogsOnly(ctx, point, force)
534→	if restoreErr != nil || len(sessions) == 0 {
535→		// Fall back to single-session restore (e.g., old checkpoints without agent metadata)
536→		return resumeSingleSession(ctx, ag, sessionID, checkpointID, repoRoot, force)
537→	}
538→
539→	logging.Debug(logCtx, "resume session completed",
540→		slog.String("checkpoint_id", checkpointID.String()),
541→		slog.Int("session_count", len(sessions)),
542→	)
543→
544→	return displayRestoredSessions(sessions)
545→}
