547→// displayRestoredSessions sorts sessions by CreatedAt and prints resume commands.
548→// Used by both resumeSession (single checkpoint) and resumeMultipleCheckpoints (squash merge).
549→func displayRestoredSessions(sessions []strategy.RestoredSession) error {
550→	sort.Slice(sessions, func(i, j int) bool {
551→		return sessions[i].CreatedAt.Before(sessions[j].CreatedAt)
552→	})
553→
554→	if len(sessions) > 1 {
555→		fmt.Fprintf(os.Stderr, "\nRestored %d sessions. To continue, run:\n", len(sessions))
556→	} else if len(sessions) == 1 {
557→		fmt.Fprintf(os.Stderr, "Session: %s\n", sessions[0].SessionID)
558→		fmt.Fprintf(os.Stderr, "\nTo continue this session, run:\n")
559→	}
560→
561→	for i, sess := range sessions {
562→		sessionAgent, err := strategy.ResolveAgentForRewind(sess.Agent)
563→		if err != nil {
564→			return fmt.Errorf("failed to resolve agent for session %s: %w", sess.SessionID, err)
565→		}
566→		cmd := sessionAgent.FormatResumeCommand(sess.SessionID)
567→
568→		isLast := i == len(sessions)-1
569→		switch {
570→		case len(sessions) > 1 && isLast && sess.Prompt != "":
571→			fmt.Fprintf(os.Stderr, "  %s  # %s (most recent)\n", cmd, sess.Prompt)
572→		case len(sessions) > 1 && isLast:
573→			fmt.Fprintf(os.Stderr, "  %s  # (most recent)\n", cmd)
574→		case sess.Prompt != "":
575→			fmt.Fprintf(os.Stderr, "  %s  # %s\n", cmd, sess.Prompt)
576→		default:
577→			fmt.Fprintf(os.Stderr, "  %s\n", cmd)
578→		}
579→	}
580→
581→	return nil
582→}
