584→// resumeSingleSession restores a single session (fallback when multi-session restore fails).
585→// Always overwrites existing session logs to ensure consistency with checkpoint state.
586→// If force is false, prompts for confirmation when local log has newer timestamps.
587→func resumeSingleSession(ctx context.Context, ag agent.Agent, sessionID string, checkpointID id.CheckpointID, repoRoot string, force bool) error {
588→	sessionLogPath, err := resolveTranscriptPath(ctx, sessionID, ag)
589→	if err != nil {
590→		return fmt.Errorf("failed to resolve transcript path: %w", err)
591→	}
592→
593→	if checkpointID.IsEmpty() {
594→		logging.Debug(ctx, "resume session: empty checkpoint ID",
595→			slog.String("checkpoint_id", checkpointID.String()),
596→		)
597→		fmt.Fprintf(os.Stderr, "Session '%s' found in commit trailer but session log not available\n", sessionID)
598→		fmt.Fprintf(os.Stderr, "\nTo continue this session, run:\n")
599→		fmt.Fprintf(os.Stderr, "  %s\n", ag.FormatResumeCommand(sessionID))
600→		return nil
601→	}
602→
603→	logContent, _, err := checkpoint.LookupSessionLog(ctx, checkpointID)
604→	if err != nil {
605→		if errors.Is(err, checkpoint.ErrCheckpointNotFound) || errors.Is(err, checkpoint.ErrNoTranscript) {
606→			logging.Debug(ctx, "resume session completed (no metadata)",
607→				slog.String("checkpoint_id", checkpointID.String()),
608→				slog.String("session_id", sessionID),
609→			)
610→			fmt.Fprintf(os.Stderr, "Session '%s' found in commit trailer but session log not available\n", sessionID)
611→			fmt.Fprintf(os.Stderr, "\nTo continue this session, run:\n")
612→			fmt.Fprintf(os.Stderr, "  %s\n", ag.FormatResumeCommand(sessionID))
613→			return nil
614→		}
615→		logging.Error(ctx, "resume session failed",
616→			slog.String("checkpoint_id", checkpointID.String()),
617→			slog.String("session_id", sessionID),
618→			slog.String("error", err.Error()),
619→		)
620→		return fmt.Errorf("failed to get session log: %w", err)
621→	}
622→
623→	// Check if local file has newer timestamps than checkpoint
624→	if !force {
625→		localTime := paths.GetLastTimestampFromFile(sessionLogPath)
626→		checkpointTime := paths.GetLastTimestampFromBytes(logContent)
627→		status := strategy.ClassifyTimestamps(localTime, checkpointTime)
628→
629→		if status == strategy.StatusLocalNewer {
630→			sessions := []strategy.SessionRestoreInfo{{
631→				SessionID:      sessionID,
632→				Status:         status,
633→				LocalTime:      localTime,
634→				CheckpointTime: checkpointTime,
635→			}}
636→			shouldOverwrite, promptErr := strategy.PromptOverwriteNewerLogs(sessions)
637→			if promptErr != nil {
638→				return fmt.Errorf("failed to get confirmation: %w", promptErr)
639→			}
640→			if !shouldOverwrite {
641→				fmt.Fprintf(os.Stderr, "Resume cancelled. Local session log preserved.\n")
642→				return nil
643→			}
644→		}
645→	}
646→
647→	// Ensure parent directory exists
648→	if err := os.MkdirAll(filepath.Dir(sessionLogPath), 0o750); err != nil {
649→		return fmt.Errorf("failed to create session directory: %w", err)
650→	}
651→
652→	agentSession := &agent.AgentSession{
653→		SessionID:  sessionID,
654→		AgentName:  ag.Name(),
655→		RepoPath:   repoRoot,
656→		SessionRef: sessionLogPath,
657→		NativeData: logContent,
658→	}
659→
660→	// Write the session using the agent's WriteSession method
661→	if err := ag.WriteSession(ctx, agentSession); err != nil {
662→		logging.Error(ctx, "resume session failed during write",
663→			slog.String("checkpoint_id", checkpointID.String()),
664→			slog.String("session_id", sessionID),
665→			slog.String("error", err.Error()),
666→		)
667→		return fmt.Errorf("failed to write session: %w", err)
668→	}
669→
670→	logging.Debug(ctx, "resume session completed",
671→		slog.String("checkpoint_id", checkpointID.String()),
672→		slog.String("session_id", sessionID),
673→	)
674→
675→	fmt.Fprintf(os.Stderr, "Session restored to: %s\n", sessionLogPath)
676→	fmt.Fprintf(os.Stderr, "Session: %s\n", sessionID)
677→	fmt.Fprintf(os.Stderr, "\nTo continue this session, run:\n")
678→	fmt.Fprintf(os.Stderr, "  %s\n", ag.FormatResumeCommand(sessionID))
679→
680→	return nil
681→}
