683→func promptFetchFromRemote(branchName string) (bool, error) {
684→	var confirmed bool
685→
686→	form := NewAccessibleForm(
687→		huh.NewGroup(
688→			huh.NewConfirm().
689→				Title(fmt.Sprintf("Branch '%s' not found locally. Fetch from origin?", branchName)).
690→				Value(&confirmed),
691→		),
692→	)
