278→// createCheckpointOnMetadataBranchWithID creates a checkpoint on the entire/checkpoints/v1 branch
279→// with a caller-specified checkpoint ID. Returns the checkpoint ID.
280→func createCheckpointOnMetadataBranchWithID(t *testing.T, repo *git.Repository, sessionID string, checkpointID id.CheckpointID) id.CheckpointID {
281→	t.Helper()
282→
283→	// Get existing metadata branch or create it
284→	if err := strategy.EnsureMetadataBranch(repo); err != nil {
285→		t.Fatalf("Failed to ensure metadata branch: %v", err)
286→	}
287→
288→	refName := plumbing.NewBranchReferenceName(paths.MetadataBranchName)
289→	ref, err := repo.Reference(refName, true)
290→	if err != nil {
291→		t.Fatalf("Failed to get metadata branch ref: %v", err)
292→	}
293→
294→	parentCommit, err := repo.CommitObject(ref.Hash())
295→	if err != nil {
296→		t.Fatalf("Failed to get parent commit: %v", err)
297→	}
298→
299→	// Create metadata content
300→	metadataJSON := fmt.Sprintf(`{
301→  "checkpoint_id": %q,
302→  "session_id": %q,
303→  "created_at": "2025-01-01T00:00:00Z"
304→}`, checkpointID.String(), sessionID)
305→
306→	// Create blob for metadata
307→	blob := repo.Storer.NewEncodedObject()
308→	blob.SetType(plumbing.BlobObject)
309→	writer, err := blob.Writer()
310→	if err != nil {
311→		t.Fatalf("Failed to create blob writer: %v", err)
312→	}
313→	if _, err := writer.Write([]byte(metadataJSON)); err != nil {
314→		t.Fatalf("Failed to write blob: %v", err)
315→	}
316→	if err := writer.Close(); err != nil {
317→		t.Fatalf("Failed to close writer: %v", err)
318→	}
319→	metadataBlobHash, err := repo.Storer.SetEncodedObject(blob)
320→	if err != nil {
321→		t.Fatalf("Failed to store blob: %v", err)
322→	}
323→
324→	// Create session log blob
325→	logBlob := repo.Storer.NewEncodedObject()
326→	logBlob.SetType(plumbing.BlobObject)
327→	logWriter, err := logBlob.Writer()
328→	if err != nil {
329→		t.Fatalf("Failed to create log blob writer: %v", err)
330→	}
331→	if _, err := logWriter.Write([]byte(`{"type":"test"}`)); err != nil {
332→		t.Fatalf("Failed to write log blob: %v", err)
333→	}
334→	if err := logWriter.Close(); err != nil {
335→		t.Fatalf("Failed to close log writer: %v", err)
336→	}
337→	logBlobHash, err := repo.Storer.SetEncodedObject(logBlob)
338→	if err != nil {
339→		t.Fatalf("Failed to store log blob: %v", err)
340→	}
341→
342→	// Build tree structure: <id[:2]>/<id[2:]>/metadata.json
343→	shardedPath := checkpointID.Path()
344→	checkpointIDStr := checkpointID.String()
345→
346→	// Create checkpoint tree with metadata and transcript files
347→	// Entries must be sorted alphabetically
348→	checkpointTree := object.Tree{
349→		Entries: []object.TreeEntry{
350→			{Name: paths.TranscriptFileName, Mode: filemode.Regular, Hash: logBlobHash},
351→			{Name: paths.MetadataFileName, Mode: filemode.Regular, Hash: metadataBlobHash},
352→		},
353→	}
354→	checkpointTreeObj := repo.Storer.NewEncodedObject()
355→	if err := checkpointTree.Encode(checkpointTreeObj); err != nil {
356→		t.Fatalf("Failed to encode checkpoint tree: %v", err)
357→	}
358→	checkpointTreeHash, err := repo.Storer.SetEncodedObject(checkpointTreeObj)
359→	if err != nil {
360→		t.Fatalf("Failed to store checkpoint tree: %v", err)
361→	}
362→
363→	// Create inner shard tree (id[2:])
364→	innerTree := object.Tree{
365→		Entries: []object.TreeEntry{
366→			{Name: checkpointIDStr[2:], Mode: filemode.Dir, Hash: checkpointTreeHash},
367→		},
368→	}
369→	innerTreeObj := repo.Storer.NewEncodedObject()
370→	if err := innerTree.Encode(innerTreeObj); err != nil {
371→		t.Fatalf("Failed to encode inner tree: %v", err)
372→	}
373→	innerTreeHash, err := repo.Storer.SetEncodedObject(innerTreeObj)
374→	if err != nil {
375→		t.Fatalf("Failed to store inner tree: %v", err)
376→	}
377→
378→	// Get existing tree entries from parent
379→	parentTree, err := parentCommit.Tree()
380→	if err != nil {
381→		t.Fatalf("Failed to get parent tree: %v", err)
382→	}
383→
384→	// Build new root tree with shard bucket
385→	var rootEntries []object.TreeEntry
386→	for _, entry := range parentTree.Entries {
387→		if entry.Name != shardedPath[:2] {
388→			rootEntries = append(rootEntries, entry)
389→		}
390→	}
391→	rootEntries = append(rootEntries, object.TreeEntry{
392→		Name: checkpointIDStr[:2],
393→		Mode: filemode.Dir,
394→		Hash: innerTreeHash,
395→	})
396→
397→	rootTree := object.Tree{Entries: rootEntries}
398→	rootTreeObj := repo.Storer.NewEncodedObject()
399→	if err := rootTree.Encode(rootTreeObj); err != nil {
400→		t.Fatalf("Failed to encode root tree: %v", err)
401→	}
402→	rootTreeHash, err := repo.Storer.SetEncodedObject(rootTreeObj)
403→	if err != nil {
404→		t.Fatalf("Failed to store root tree: %v", err)
405→	}
406→
407→	// Create commit on metadata branch
408→	commit := &object.Commit{
409→		Author: object.Signature{
410→			Name:  "Test",
411→			Email: "test@example.com",
412→			When:  parentCommit.Author.When,
413→		},
414→		Committer: object.Signature{
415→			Name:  "Test",
416→			Email: "test@example.com",
417→			When:  parentCommit.Author.When,
418→		},
419→		Message:      "Add checkpoint metadata",
420→		TreeHash:     rootTreeHash,
421→		ParentHashes: []plumbing.Hash{parentCommit.Hash},
422→	}
423→	commitObj := repo.Storer.NewEncodedObject()
