432→	// Update metadata branch ref
433→	newRef := plumbing.NewHashReference(refName, commitHash)
434→	if err := repo.Storer.SetReference(newRef); err != nil {
435→		t.Fatalf("Failed to update metadata branch: %v", err)
436→	}
